import { useEffect, useMemo, useState } from "react";
import { useNavigate, useParams, useSearchParams } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";
import api from "../utils/api";
import { CATEGORY_META, getBookingMode } from "../utils/categories";

export default function BookingPage() {
  const { id } = useParams();
  const [sp] = useSearchParams();
  const nav = useNavigate();
  const { user } = useAuth();

  const [place, setPlace] = useState(null);
  const [services, setServices] = useState([]);
  const [staffs, setStaffs] = useState([]);
  const [slots, setSlots] = useState([]);
  const [bookedTargetIds, setBookedTargetIds] = useState({
    staffIds: [],
    tableIds: [],
  });

  const [serviceId, setServiceId] = useState(sp.get("serviceId") || "");
  const [staffId, setStaffId] = useState("");
  const [tableId, setTableId] = useState("");
  const [date, setDate] = useState(new Date().toISOString().slice(0, 10));
  const [time, setTime] = useState("");
  const [note, setNote] = useState("");
  const [msg, setMsg] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    api.get(`/places/${id}`).then(({ data }) => {
      const p = data.data;
      setPlace(p);
      setServices(p.services || []);
      setStaffs(p.staffs || []);
      if (!serviceId && p.services?.[0]) setServiceId(p.services[0]._id);
    });
  }, [id, serviceId]);

  const mode = useMemo(() => getBookingMode(place?.category), [place]);

  useEffect(() => {
    if (!place || !date) return;

    const q = new URLSearchParams({ placeId: place._id, date });
    if (mode === "staff" && staffId) q.set("staffId", staffId);
    if (mode === "table" && tableId) q.set("tableId", tableId);

    api
      .get(`/bookings/availability?${q.toString()}`)
      .then(({ data }) => setSlots(data.data || []))
      .catch(() => setSlots([]));
  }, [place, date, staffId, tableId, mode]);

  useEffect(() => {
    if (!place || !date || !time) return;

    const datetime = `${date}T${time}:00`;
    api
      .get(`/bookings/booked-targets?placeId=${place._id}&datetime=${datetime}`)
      .then(({ data }) =>
        setBookedTargetIds(data.data || { staffIds: [], tableIds: [] }),
      )
      .catch(() => setBookedTargetIds({ staffIds: [], tableIds: [] }));
  }, [place, date, time]);

  const selectedService = services.find((s) => s._id === serviceId);

  const groupedTables = useMemo(() => {
    if (!place?.tables?.length) return [];
    const sorted = [...place.tables].sort((a, b) =>
      `${a.row}${a.col}`.localeCompare(`${b.row}${b.col}`),
    );
    return sorted;
  }, [place]);

  const canSubmit =
    !!serviceId &&
    !!date &&
    !!time &&
    (mode !== "staff" || !!staffId) &&
    (mode !== "table" || !!tableId);

  const submit = async () => {
    if (!user) {
      nav("/login");
      return;
    }

    setLoading(true);
    setMsg("");

    try {
      await api.post("/bookings", {
        placeId: id,
        serviceId,
        staffId: mode === "staff" ? staffId : undefined,
        tableId: mode === "table" ? tableId : undefined,
        datetime: `${date}T${time}:00`,
        note,
      });
      nav("/my-bookings");
    } catch (e) {
      setMsg(e.response?.data?.message || "Захиалга хийхэд алдаа гарлаа");
    }

    setLoading(false);
  };

  if (!place) {
    return (
      <div style={{ padding: 24, color: "var(--muted)" }}>Ачаалж байна...</div>
    );
  }

  const category = CATEGORY_META[place.category] || {
    icon: "📍",
    label: place.category,
  };

  return (
    <div style={{ maxWidth: 980, margin: "0 auto", padding: "26px 20px" }}>
      <div style={{ marginBottom: 20 }}>
        <div style={{ color: "var(--teal)", fontSize: 13 }}>
          {category.icon} {category.label}
        </div>
        <h1 style={{ marginTop: 6, marginBottom: 4 }}>Захиалга</h1>
        <div style={{ color: "var(--muted)", fontSize: 13 }}>{place.name}</div>
      </div>

      <div
        style={{ display: "grid", gridTemplateColumns: "1fr 320px", gap: 20 }}
      >
        <div className="card">
          <div style={{ display: "grid", gap: 14 }}>
            <div>
              <label>Үйлчилгээ</label>
              <select
                className="input"
                value={serviceId}
                onChange={(e) => setServiceId(e.target.value)}
              >
                <option value="">-- Сонгох --</option>
                {services.map((s) => (
                  <option key={s._id} value={s._id}>
                    {s.name} • {s.duration} мин • ₮
                    {(s.price || 0).toLocaleString()}
                  </option>
                ))}
              </select>
            </div>

            {mode === "staff" && (
              <div>
                <label>Мэргэжилтэн сонгох</label>
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(2, minmax(0, 1fr))",
                    gap: 8,
                  }}
                >
                  {staffs.map((st) => {
                    const blocked =
                      bookedTargetIds.staffIds.includes(st._id) && !!time;
                    const active = staffId === st._id;
                    return (
                      <button
                        key={st._id}
                        disabled={blocked}
                        onClick={() => setStaffId(st._id)}
                        style={{
                          border: `1px solid ${active ? "var(--blue)" : blocked ? "var(--red)" : "var(--border)"}`,
                          background: active
                            ? "rgba(37,99,235,0.15)"
                            : "var(--surface)",
                          color: blocked ? "var(--muted)" : "var(--text)",
                          borderRadius: 8,
                          padding: "10px",
                          textAlign: "left",
                          cursor: blocked ? "not-allowed" : "pointer",
                        }}
                      >
                        <div style={{ fontWeight: 600, fontSize: 13 }}>
                          {st.name}
                        </div>
                        <div style={{ fontSize: 11, color: "var(--muted)" }}>
                          {st.role}
                        </div>
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            {mode === "table" && (
              <div>
                <label>Ширээ сонгох (2D схем)</label>
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(3, minmax(0, 1fr))",
                    gap: 8,
                  }}
                >
                  {groupedTables.map((tb) => {
                    const blocked =
                      bookedTargetIds.tableIds.includes(tb._id) && !!time;
                    const active = tableId === tb._id;
                    return (
                      <button
                        key={tb._id}
                        disabled={blocked}
                        onClick={() => setTableId(tb._id)}
                        style={{
                          border: `1px solid ${active ? "var(--blue)" : blocked ? "var(--red)" : "var(--border)"}`,
                          background: active
                            ? "rgba(37,99,235,0.15)"
                            : "var(--surface)",
                          color: blocked ? "var(--muted)" : "var(--text)",
                          borderRadius: 8,
                          padding: "10px",
                          cursor: blocked ? "not-allowed" : "pointer",
                        }}
                      >
                        <div style={{ fontWeight: 600, fontSize: 13 }}>
                          {tb.name}
                        </div>
                        <div style={{ fontSize: 11, color: "var(--muted)" }}>
                          {tb.type} • {tb.capacity} хүн
                        </div>
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: 10,
              }}
            >
              <div>
                <label>Өдөр</label>
                <input
                  type="date"
                  className="input"
                  value={date}
                  min={new Date().toISOString().slice(0, 10)}
                  onChange={(e) => setDate(e.target.value)}
                />
              </div>
              <div>
                <label>Цаг</label>
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(3, minmax(0, 1fr))",
                    gap: 6,
                  }}
                >
                  {slots.map((s) => (
                    <button
                      key={s.time}
                      onClick={() => setTime(s.time)}
                      disabled={!s.available}
                      style={{
                        border: "1px solid var(--border)",
                        borderRadius: 8,
                        padding: "8px 6px",
                        background:
                          time === s.time ? "var(--blue)" : "var(--surface)",
                        color:
                          time === s.time
                            ? "#fff"
                            : s.available
                              ? "var(--text)"
                              : "var(--muted)",
                        opacity: s.available ? 1 : 0.5,
                      }}
                    >
                      {s.time}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div>
              <label>Тэмдэглэл</label>
              <textarea
                className="input"
                value={note}
                onChange={(e) => setNote(e.target.value)}
                rows={3}
                style={{ resize: "vertical" }}
              />
            </div>

            {msg ? (
              <div style={{ color: "var(--red)", fontSize: 13 }}>{msg}</div>
            ) : null}

            <button
              className="btn btn-primary"
              onClick={submit}
              disabled={!canSubmit || loading}
            >
              {loading ? "Илгээж байна..." : "Захиалга баталгаажуулах"}
            </button>
          </div>
        </div>

        <div
          className="card"
          style={{ height: "fit-content", position: "sticky", top: 76 }}
        >
          <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 8 }}>
            Хураангуй
          </div>
          <div style={{ display: "grid", gap: 8, fontSize: 13 }}>
            <div>
              Газар: <b>{place.name}</b>
            </div>
            <div>
              Үйлчилгээ: <b>{selectedService?.name || "—"}</b>
            </div>
            <div>
              Огноо: <b>{date || "—"}</b>
            </div>
            <div>
              Цаг: <b>{time || "—"}</b>
            </div>
            {mode === "staff" ? (
              <div>
                Мэргэжилтэн:{" "}
                <b>{staffs.find((s) => s._id === staffId)?.name || "—"}</b>
              </div>
            ) : null}
            {mode === "table" ? (
              <div>
                Ширээ:{" "}
                <b>
                  {place.tables?.find((t) => t._id === tableId)?.name || "—"}
                </b>
              </div>
            ) : null}
            <div>
              Төлбөр:{" "}
              <b style={{ color: "var(--blue)" }}>
                ₮{(selectedService?.price || 0).toLocaleString()}
              </b>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
